// Cloudflare Pages Function — dynamic OG tags for shared links
// Works for:
//   ?news=<set_id>       → 카드뉴스
//   ?board=<post_id>     → 자유게시판 글
//   ?recruit=<id>        → 채용공고

const SB_URL = 'https://rzllpymhtygnooduevgf.supabase.co';
const TRUSTED_IMAGE_PREFIX = `${SB_URL}/storage/`;
const DEFAULT_OG_IMAGE = 'https://insureconnect-hub.pages.dev/logo-full.png';

// og:image URL이 신뢰 도메인(Supabase Storage)인지 검증
function safeImage(url) {
  if (typeof url !== 'string') return DEFAULT_OG_IMAGE;
  if (url.startsWith(TRUSTED_IMAGE_PREFIX)) return url;
  return DEFAULT_OG_IMAGE;
}

// anon key 은 index.html 에서 정규식으로 추출 (빌드마다 값 바뀌어도 안전)
function extractAnon(html) {
  const m = html.match(/const\s+SB_ANON\s*=\s*['"]([^'"]+)['"]/);
  return m ? m[1] : null;
}

function esc(s) {
  return (s || '').replace(/&/g,'&amp;').replace(/"/g,'&quot;')
    .replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

async function fetchCardNews(sid, anon) {
  const url = `${SB_URL}/rest/v1/ic_card_news?set_id=eq.${encodeURIComponent(sid)}&order=sort_order.asc&select=title,file_url,file_type,created_at`;
  const res = await fetch(url, { headers: { apikey: anon, Authorization: `Bearer ${anon}` } });
  if (!res.ok) return null;
  const rows = await res.json();
  if (!rows || !rows.length) return null;
  const cover = rows.find(r => r.file_type === 'image') || rows[0];
  return {
    title: rows[0].title || '인슈어커넥트 카드뉴스',
    image: cover && cover.file_type === 'image' ? cover.file_url : null,
    count: rows.length,
  };
}

async function fetchBoardPost(id, anon) {
  const url = `${SB_URL}/rest/v1/ic_posts?id=eq.${encodeURIComponent(id)}&select=title,content,author_role,author_name,is_notice&limit=1`;
  const res = await fetch(url, { headers: { apikey: anon, Authorization: `Bearer ${anon}` } });
  if (!res.ok) return null;
  const rows = await res.json();
  if (!rows || !rows.length) return null;
  return rows[0];
}

async function fetchRecruit(id, anon) {
  const url = `${SB_URL}/rest/v1/ic_recruitments?id=eq.${encodeURIComponent(id)}&select=title,company_name,description,file_url,file_type&limit=1`;
  const res = await fetch(url, { headers: { apikey: anon, Authorization: `Bearer ${anon}` } });
  if (!res.ok) return null;
  const rows = await res.json();
  if (!rows || !rows.length) return null;
  return rows[0];
}

function buildOg({ title, description, image, url }) {
  const t = esc(title);
  const d = esc(description);
  const i = esc(image);
  const u = esc(url);
  return `<!-- OG:START -->
  <meta property="og:type" content="article">
  <meta property="og:site_name" content="InsureConnect">
  <meta property="og:title" content="${t}">
  <meta property="og:description" content="${d}">
  <meta property="og:image" content="${i}">
  <meta property="og:image:width" content="1200">
  <meta property="og:image:height" content="630">
  <meta property="og:url" content="${u}">
  <meta name="twitter:card" content="summary_large_image">
  <meta name="twitter:title" content="${t}">
  <meta name="twitter:description" content="${d}">
  <meta name="twitter:image" content="${i}">
  <!-- OG:END -->`;
}

export async function onRequest(context) {
  const { request, next } = context;
  const url = new URL(request.url);

  // 루트/HTML 요청만 처리
  const isRootHtml =
    (url.pathname === '/' || url.pathname === '/index.html') &&
    request.method === 'GET';
  if (!isRootHtml) return next();

  const newsId    = url.searchParams.get('news');
  const boardId   = url.searchParams.get('board');
  const recruitId = url.searchParams.get('recruit');
  if (!newsId && !boardId && !recruitId) return next();

  // 원본 index.html 가져오기
  const originalRes = await next();
  const ctype = originalRes.headers.get('content-type') || '';
  if (!ctype.includes('text/html')) return originalRes;

  const html = await originalRes.text();
  const anon = extractAnon(html);
  if (!anon) return new Response(html, { status: originalRes.status, headers: originalRes.headers });

  let og = null;
  try {
    if (newsId) {
      const data = await fetchCardNews(newsId, anon);
      if (data) {
        og = buildOg({
          title: `${data.title} · InsureConnect 카드뉴스`,
          description: `${data.count}장의 카드뉴스로 확인하는 최신 보험 이슈. 탭 한번으로 상세히 보기.`,
          image: safeImage(data.image),
          url: url.toString(),
        });
      }
    } else if (boardId) {
      const p = await fetchBoardPost(boardId, anon);
      if (p) {
        const titlePrefix = p.is_notice ? '[공지] ' : '';
        og = buildOg({
          title: `${titlePrefix}${p.title} · InsureConnect 자유게시판`,
          description: (p.content || '').slice(0, 150),
          image: DEFAULT_OG_IMAGE,
          url: url.toString(),
        });
      }
    } else if (recruitId) {
      const r = await fetchRecruit(recruitId, anon);
      if (r) {
        og = buildOg({
          title: `${r.company_name ? '[' + r.company_name + '] ' : ''}${r.title} · InsureConnect 채용공고`,
          description: (r.description || '보험사 채용공고를 인슈어커넥트에서 확인하세요.').slice(0, 150),
          image: r.file_type === 'image' ? safeImage(r.file_url) : DEFAULT_OG_IMAGE,
          url: url.toString(),
        });
      }
    }
  } catch (_) {}

  if (!og) return new Response(html, { status: originalRes.status, headers: originalRes.headers });

  const rewritten = html.replace(
    /<!-- OG:START -->[\s\S]*?<!-- OG:END -->/,
    og
  );

  return new Response(rewritten, {
    status: originalRes.status,
    headers: {
      ...Object.fromEntries(originalRes.headers),
      'content-type': 'text/html; charset=utf-8',
      'cache-control': 'public, max-age=60, s-maxage=300',
    },
  });
}
